function getEditorialInsights(p) { const s=p.stats||{}; const production=(s.ppg||0)>=20?'Elite':(s.ppg||0)>=14?'Alta':'Funcional'; const consistency=(s.ts||0)>=60?'Alta':(s.ts||0)>=55?'Estavel':'Em construcao'; const trajectory=p.age<=19?'Ascendente':(p.rank||99)<=20?'Consolidada':'Situacional'; return [{label:'Producao ofensiva',value:production,Icon:BarChart3,color:'#a79be8'},{label:'Consistencia',value:consistency,Icon:Crosshair,color:'#8bbfe8'},{label:'Trajetoria',value:trajectory,Icon:TrendingUp,color:'#6fbf9c'}] }
function getNBATranslationCards(p) { const base=getNBATranslation(p); const colors=['#a79be8','#8bbfe8','#e8a6a6']; const icons=[User,Puzzle,AlertTriangle]; const desc=['Traduz o primeiro papel que pode gerar minutos sem exigir protagonismo imediato.','Define o ecossistema ofensivo e defensivo que melhor acelera a traducao.','Ponto que mais pode limitar eficiencia, minutos ou confianca no proximo nivel.']; return base.map(([label,value],i)=>({label,value,description:desc[i],color:colors[i],Icon:icons[i]})) }
function getDraftValueContext(p, currentPick) { const data=getDraftValue(p,currentPick), status=data[0], color=data[1], rank=p.rank||'-', pick=currentPick||p.rank||'-'; const text=status==='Steal'?'Valor acima da posicao atual do board.':status==='Reach'?'Aposta acima da expectativa atual de mercado.':'Valor alinhado a expectativa do board.'; return [{label:'RANK ESPERADO',value:'#'+rank,sub:'Top '+rank+' do Big Board',Icon:ListOrdered,color:'#a79be8'},{label:'MOCK POSITION',value:'#'+pick,sub:'Selecionado atualmente no '+pick+' pick',Icon:Target,color:'#8bbfe8'},{label:'VALUE',value:status,sub:text,Icon:Gem,color}] }
function Title({ eyebrow, title }) { return <div className="mb-4"><div className={cn(dsTypography.sectionLabel, 'text-[9px] tracking-[0.28em] text-lo')}>{eyebrow}</div><h2 className={cn(dsTypography.cardTitle, 'mt-1')}>{title}</h2></div> }
function Shell({ children, className='' }) { return <motion.section whileHover={{y:-1}} className={glassCard('primary', 'relative overflow-hidden p-5 ring-1 ring-white/35 transition-all duration-300 '+className)} style={{boxShadow:'0 24px 70px rgba(40,36,32,.075), inset 1px 1px 0 rgba(255,255,255,.68)'}}><span className="pointer-events-none absolute inset-x-0 top-0 h-28 bg-gradient-to-b from-white/60 to-transparent opacity-70"/><span className="pointer-events-none absolute -right-16 -top-16 h-44 w-44 rounded-full bg-white/35 blur-3xl"/><div className="relative">{children}</div></motion.section> }
function Bio({ label, value, color }) { return <div className="flex items-center justify-between border-b border-[#d8d3cc]/70 py-3 last:border-b-0"><span className="font-mono text-[9px] font-bold tracking-[0.22em] text-lo">{label}</span><span className="font-mono text-lg font-black" style={{color}}>{value}</span></div> }
function StatMini({ label, value, color }) { return <div className="flex items-center justify-between border-b border-[#d8d3cc]/70 py-3 last:border-b-0"><span className="font-mono text-[9px] font-bold tracking-[0.22em] text-lo">{label}</span><span className="font-mono text-xl font-black" style={{color}}>{value}</span></div> }
function MetricPanel({ children }) { return <div className={'mb-4 rounded-[26px] px-4 py-2 '+glass.inner}>{children}</div> }
function MiniIcon({ label, color }) { const kind = label.toLowerCase(); return <svg viewBox="0 0 48 48" className="h-8 w-8" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" style={{color}}>{kind.includes('shoot')?<><circle cx="24" cy="24" r="14"/><circle cx="24" cy="24" r="7"/><circle cx="24" cy="24" r="2" fill="currentColor"/></>:kind.includes('score')?<path d="M24 5l4 13 13 4-13 4-4 17-4-17-13-4 13-4 4-13z"/>:kind.includes('play')?<><circle cx="13" cy="18" r="4"/><circle cx="35" cy="14" r="4"/><circle cx="31" cy="34" r="4"/><path d="M17 18l14-3M16 21l12 10"/></>:kind.includes('rebound')?<><path d="M11 31c5 7 21 7 26 0"/><path d="M14 25c2-7 18-7 20 0"/><path d="M24 10v26M17 17h14"/></>:(kind.includes('rim')||kind.includes('defend'))?<path d="M24 6l14 6v10c0 10-6 17-14 20-8-3-14-10-14-20V12l14-6z"/>:<><path d="M18 12c-5 0-8 4-8 9 0 3 1 5 3 7-1 5 3 9 8 8 2 4 9 4 11 0 5 1 9-3 8-8 2-2 3-4 3-7 0-5-3-9-8-9-2-6-15-6-17 0z"/><path d="M20 17c-2 2-2 5 0 7M29 17c2 2 2 5 0 7"/></>}</svg> }
function Badge({ label, text, accent, bg }) { return <div className="flex min-h-[132px] flex-col gap-3 rounded-[22px] p-3" style={{background:bg,boxShadow:'4px 4px 10px #d4d0ca, -4px -4px 10px #fff'}}><div className="flex h-12 w-12 shrink-0 items-center justify-center rounded-full" style={{background:'#edeae4',boxShadow:'inset 4px 4px 9px #d4d0ca, inset -4px -4px 9px #fff'}}><MiniIcon label={label} color={accent}/></div><div><div className="font-mono text-[9px] font-bold tracking-[0.18em]" style={{color:accent}}>{label}</div><p className="mt-1 text-xs leading-5 text-mid">{text}</p></div></div> }
function Nav({ active, setActive, tier }) { return <nav className="mt-2 grid gap-1">{TABS.map(([id,label,eyebrow])=>{const on=active===id;return <motion.button key={id} onClick={()=>setActive(id)} className={(on?glass.chip:'')+' group border-l-2 px-3 py-2 text-left transition-all duration-300'} whileHover={{x:3,y:-1}} whileTap={{scale:.98}} style={{borderColor:on?tier.text:'transparent',color:on?tier.text:'#7a7570',boxShadow:on?'0 10px 26px '+tier.color+'20':'none'}}><span className="block font-mono text-[7px] font-bold tracking-[0.24em] text-lo">{eyebrow}</span><span className="block font-display text-xl font-bold">{label}</span></motion.button>})}</nav> }
function ProfileTabs({ active, setActive, tier }) { return <nav className={dsTabs.bar} aria-label="Navegacao do perfil">{TABS.map(([id,label,eyebrow])=>{const on=active===id;return <motion.button key={id} type="button" onClick={()=>setActive(id)} whileHover={{y:-2}} whileTap={{scale:.98}} className={dsTabs.item} style={{background:on?'linear-gradient(145deg, rgba(255,255,255,.76), rgba(255,255,255,.48))':'transparent',boxShadow:on?'0 12px 28px '+tier.color+'24, inset 1px 1px 0 rgba(255,255,255,.82)':'none',color:on?tier.text:'#7a7570'}} aria-pressed={on}><span className="block font-mono text-[7px] font-black uppercase tracking-[.16em] text-lo">{eyebrow}</span><span className="block truncate font-sans text-sm font-extrabold leading-tight">{label}</span></motion.button>})}</nav> }
function Radar({ attrs={}, accent }) { const center=150,maxR=96, rings=[.25,.5,.75,1], poly=r=>RADAR.map((_,i)=>{const ang=-Math.PI/2+i*2*Math.PI/RADAR.length;return (center+Math.cos(ang)*maxR*r)+','+(center+Math.sin(ang)*maxR*r)}).join(' '), data=RADAR.map((a,i)=>{const v=typeof attrs[a]==='number'?attrs[a]:5,ang=-Math.PI/2+i*2*Math.PI/RADAR.length,r=v/10*maxR;return{a,v,x:center+Math.cos(ang)*r,y:center+Math.sin(ang)*r,lx:center+Math.cos(ang)*(maxR+38),ly:center+Math.sin(ang)*(maxR+38)}}), pts=data.map(d=>d.x+','+d.y).join(' '); return <div className="relative mx-auto aspect-square w-full max-w-[430px] rounded-full border border-white/35 bg-white/25 p-8 backdrop-blur-xl" style={{boxShadow:'0 20px 60px rgba(0,0,0,.10), inset 8px 8px 18px rgba(210,204,196,.26), inset -8px -8px 18px rgba(255,255,255,.62), 0 0 42px '+accent+'24'}}><span className="pointer-events-none absolute inset-8 rounded-full" style={{background:'radial-gradient(circle at 50% 45%, '+accent+'1f, transparent 62%)'}}/><svg viewBox="0 0 300 300" className="relative h-full w-full overflow-visible"><defs><filter id="radarGlow"><feGaussianBlur stdDeviation="4" result="blur"/><feMerge><feMergeNode in="blur"/><feMergeNode in="SourceGraphic"/></feMerge></filter></defs>{rings.map(r=><motion.polygon key={r} points={poly(r)} fill="none" stroke="#d9d4cc" strokeWidth={r===1?1.6:1} initial={{opacity:0,scale:.85,transformOrigin:'150px 150px'}} whileInView={{opacity:.62,scale:1}} viewport={{once:true}}/>)}{RADAR.map((_,i)=>{const ang=-Math.PI/2+i*2*Math.PI/RADAR.length;return <line key={i} x1={center} y1={center} x2={center+Math.cos(ang)*maxR} y2={center+Math.sin(ang)*maxR} stroke="#dfdbd4" strokeWidth="1" opacity=".7"/>})}<motion.polygon points={pts} fill={accent} fillOpacity=".24" stroke={accent} strokeWidth="3" filter="url(#radarGlow)" initial={{scale:.7,opacity:0,transformOrigin:'150px 150px'}} whileInView={{scale:1,opacity:1}} viewport={{once:true}} transition={{type:'spring',stiffness:95,damping:20}}/>{data.map(d=><g key={d.a}><circle cx={d.x} cy={d.y} r="5" fill="#fff" stroke={accent} strokeWidth="2.4" filter="url(#radarGlow)"/><text x={d.lx} y={d.ly-4} textAnchor={Math.abs(d.lx-center)<8?'middle':d.lx<center?'end':'start'} fill="#5f5852" fontSize="10.5" fontWeight="800" fontFamily="monospace">{d.a}</text><text x={d.lx} y={d.ly+9} textAnchor={Math.abs(d.lx-center)<8?'middle':d.lx<center?'end':'start'} fill={accent} fontSize="9" fontWeight="900" fontFamily="monospace">{num(d.v)} / 10</text></g>)}</svg></div> }
function ProjectionOrb({ label, value, color, onChange }) { const [drag,setDrag]=useState(null), shown=drag?.value ?? Math.round(value); return <motion.div drag="y" dragConstraints={{top:0,bottom:0}} dragElastic={0.02} dragMomentum={false} onDragStart={()=>setDrag({start:Math.round(value),value:Math.round(value)})} onDrag={(_,info)=>{const base=drag?.start ?? Math.round(value), next=clamp(base-Math.trunc(info.offset.y/64),35,99);setDrag({start:base,value:next});onChange(next)}} onDragEnd={()=>setDrag(null)} whileHover={{scale:1.025,y:-3}} whileTap={{scale:.97}} className="mx-auto flex h-44 w-44 cursor-ns-resize touch-none flex-col items-center justify-center rounded-full text-center" style={{background:`radial-gradient(circle at 30% 22%, rgba(255,255,255,.92), transparent 30%), radial-gradient(circle at 72% 78%, ${color}55, transparent 44%), #edeae4`,boxShadow:`inset 10px 10px 22px #d4d0ca, inset -10px -10px 22px #fff, 0 0 28px ${color}33`}}><div className="font-mono text-[9px] font-bold tracking-[.25em] text-lo">{label}</div><motion.div key={shown} initial={{opacity:.7,y:6}} animate={{opacity:1,y:0}} className="mt-1 font-mono text-6xl font-black leading-none" style={{color}}>{shown}</motion.div><div className="mt-3 rounded-pill px-3 py-1 font-mono text-[8px] font-bold tracking-widest" style={{color,background:'#f6f3ee',boxShadow:'inset 2px 2px 5px #d4d0ca, inset -2px -2px 5px #fff'}}>ARRASTE DEVAGAR</div></motion.div> }
function projectionRead(floor, top) { const floorText = floor < 50 ?'Exige desenvolvimento forte antes de confiar em minutos NBA,' : floor < 60 ?'Exige ser testado em contextos com menos press\u00e3o para garantir mais minutos em quadra,' : floor < 70 ?'J\u00e1 consegue impactar em seu primeiro dia de NBA,' : 'Entra na liga sendo importante para o seu time,'; const ceilingText = top < 60 ?'por\u00e9m dificilmente conseguir\u00e1 impactar em partidas importantes.' : top < 70 ?'por\u00e9m pode se tornar uma pe\u00e7a importante na engrenagem.' : top < 80 ?'por\u00e9m se bem desenvolvido pode se tornar um excelente diferencial em uma equipe vencedora.' : top < 90 ?'por\u00e9m se bem desenvolvido pode se tornar uma excelente 2\u00aa op\u00e7\u00e3o de um time vencedor.' : 'por\u00e9m pode se tornar o principal jogador do seu time.'; const label = floor < 50 ?'High risk' : floor < 60 ?'Moderate risk' : top - floor >= 25 ?'Low risk / upside play' : 'Low risk'; return [label, floorText + ' ' + ceilingText] }
function scoreToTrack(v) { return clamp(((v-35)/(99-35))*100,0,100) }
function getStyleTags(p) { const s=p.stats||{}, tags=[getPlayerArchetype(p)]; if((s.ppg||0)>=18) tags.push('Volume Scorer'); if((s.ts||0)>=60) tags.push('Efficient Engine'); if((s.threep||0)>=37) tags.push('Spacing Swing'); if((s.apg||0)>=4 || (s.astTo||0)>=1.8) tags.push('Advantage Creator'); if(Math.max(s.stlPct||0,s.blkPct||0)>=3) tags.push('Defensive Tools'); if((p.rank||99)<=10) tags.push('High Leverage Pick'); if((s.ts||0)>=58 || (p.age||21)<=19) tags.push('NBA Ready Path'); return Array.from(new Set(tags)).slice(0,5) }
function getScoutSummaryBullets(p) { const s=p.stats||{}, list=[]; if(typeof s.ppg==='number') list.push(num(s.ppg)+' PPG definem a responsabilidade ofensiva atual.'); if(typeof s.ts==='number') list.push(num(s.ts)+'% TS contextualizam a eficiencia do pacote.'); if((s.threep||0)>=37) list.push('Arremesso exterior cria caminho simples de traducao NBA.'); else if(typeof s.threep==='number' && s.threep<32) list.push('A bola de 3 e o swing skill central para estabilizar o teto.'); if(Math.max(s.stlPct||0,s.blkPct||0)>=3) list.push('Indicadores defensivos elevam o piso mesmo em papel menor.'); if(!list.length) list.push('Perfil pede leitura conjunta de papel, contexto e desenvolvimento.'); return list.slice(0,3) }
function getExecutiveDecision(p, floor, top) { const spread=top-floor; const risk=floor<50?'High':floor<60?'Moderate':'Low'; return [{label:'Floor',value:getFloorLabel(floor),score:floor,tone:'#e8a6a6'},{label:'Ceiling',value:getCeilingLabel(top),score:top,tone:'#a79be8'},{label:'Risk',value:risk,score:spread,tone:risk==='High'?'#e8a6a6':risk==='Moderate'?'#8bbfe8':'#6fbf9c'},{label:'Overall Grade',value:String(Math.round((floor+top)/2)),score:Math.round((floor+top)/2),tone:p.accentColor||'#a79be8'}] }
function getSignatureTraits(p, badges) { const s=p.stats||{}, attrs=p.scouting?.attributes||{}, sorted=(badges||badgesFor(p)).map(([label,text])=>({label,text,value:attrValue(p,label)})).sort((a,b)=>b.value-a.value), dom=getDominantAttribute(attrs), weak=getWeakestAttribute(attrs), primary=sorted[0] || {label:dom[0],text:getRadarCopy(dom[0],'strong'),value:dom[1]}, secondary=sorted[1] || {label:'Secondary Tool',text:getRadarCopy(dom[0],'strong'),value:Math.max(6,dom[1]-.6)}, swing=(typeof s.threep==='number' && s.threep<34)?{label:'Swing Skill',title:'3PT consistency',text:'O arremesso e o ponto que mais altera o teto ofensivo.',value:clamp((s.threep||28)/4.5,1,10),Icon:Target,color:'#8bbfe8'}:{label:'Swing Skill',title:(s.astTo||0)<1.3?'Decision speed':'Creation scale',text:(s.astTo||0)<1.3?'Processar decisoes sob pressao define o salto de papel.':'Aumentar criacao sem perder eficiencia muda o range.',value:clamp((s.astTo||1)*3,1,10),Icon:Crosshair,color:'#8bbfe8'}, red=(p.scouting?.weaknesses||[])[0] || getRadarCopy(weak[0],'weak'), ready=(s.ts||0)>=58?'Efficiency baseline':Math.max(s.stlPct||0,s.blkPct||0)>=3?'Defensive activity':'Role clarity'; return [{slot:'Primary Strength',title:primary.label,copy:primary.text,grade:getAttributeGrade(primary.value),value:primary.value,Icon:Zap,color:'#a79be8',featured:true},{slot:'Secondary Strength',title:secondary.label,copy:secondary.text,grade:getAttributeGrade(secondary.value),value:secondary.value,Icon:Sparkles,color:'#8bbfe8'},{slot:swing.label,title:swing.title,copy:swing.text,grade:getAttributeGrade(swing.value),value:swing.value,Icon:swing.Icon,color:swing.color},{slot:'Red Flag',title:weak[0],copy:red,grade:getAttributeGrade(weak[1]),value:weak[1],Icon:AlertTriangle,color:'#e8a6a6',risk:true},{slot:'NBA Ready Skill',title:ready,copy:'Ferramenta mais simples de traduzir para minutos iniciais em papel NBA.',grade:getAttributeGrade(Math.max(primary.value,6.4)),value:Math.max(primary.value,6.4),Icon:BadgeCheck,color:'#6fbf9c'}] }
function ExecutiveMetric({ item }) { return <motion.div whileHover={{x:3}} className={cn(glass.inner,'flex items-center justify-between rounded-[28px] px-4 py-3')}><div className="min-w-0"><div className={dsTypography.metricLabel}>{item.label}</div><div className="mt-1 truncate font-display text-xl font-black leading-tight text-ink">{item.value}</div></div><div className="font-numeric text-4xl font-extrabold leading-none" style={{color:item.tone}}>{item.score}</div></motion.div> }
function ExecutiveSummaryCard({ p, accent, tier, floor, top }) { const copy=getOverviewCopy(p), styleTags=getStyleTags(p), bullets=getScoutSummaryBullets(p); return <motion.section variants={motionPresets.card} initial="initial" animate="animate" className={glassCard('primary','relative h-full overflow-hidden rounded-[36px] border-white/45 bg-white/42 p-6 md:p-7')} style={{boxShadow:'0 28px 86px rgba(40,36,32,.09), inset 1px 1px 0 rgba(255,255,255,.72), 0 0 54px '+accent+'14'}}><span className="pointer-events-none absolute inset-x-0 top-0 h-28 bg-gradient-to-b from-white/65 to-transparent opacity-75"/><span className="pointer-events-none absolute -right-20 -top-24 h-72 w-72 rounded-full blur-3xl" style={{background:accent,opacity:.16}}/><div className="relative"><div className="flex min-w-0 flex-col"><div className={cn(dsTypography.sectionLabel,'text-lo')}>EXECUTIVE PROSPECT SUMMARY</div><h2 className="mt-3 max-w-3xl font-sans text-3xl font-extrabold leading-[1.04] tracking-tight text-slate-900 md:text-4xl 3xl:text-5xl uw:text-6xl">{copy.headline}</h2><p className="mt-3 max-w-3xl text-sm font-bold leading-6 text-[#5f5852] 3xl:text-base 3xl:leading-7">{copy.subheadline}</p><div className="mt-5 flex flex-wrap gap-2"><span className="rounded-full px-3 py-1.5 font-mono text-[8px] font-black uppercase tracking-[.16em]" style={{background:tier.bg,color:tier.text}}>Tier: {p.tier}</span><span className={glass.chip+' font-mono text-[8px] font-black uppercase tracking-[.16em] text-mid'}>{p.position}</span><span className={glass.chip+' font-mono text-[8px] font-black uppercase tracking-[.16em] text-mid'}>{p.age} anos</span>{styleTags.slice(0,3).map(tag=><span key={tag} className={glass.chip+' font-mono text-[8px] font-black uppercase tracking-[.16em]'} style={{color:accent}}>{tag}</span>)}</div><div className="mt-5 rounded-[32px] border border-white/40 bg-white/32 p-5 shadow-[0_18px_52px_rgba(40,36,32,.055),inset_1px_1px_0_rgba(255,255,255,.64)] backdrop-blur-2xl"><div className={cn(dsTypography.sectionLabel,'mb-3 text-lo')}>POR QUE IMPORTA</div><p className="max-w-5xl font-sans text-sm font-semibold leading-7 text-[#4f4943] 3xl:text-base 3xl:leading-7">{copy.body}</p><div className="mt-4 grid gap-3 lg:grid-cols-3 xl:grid-cols-1 min-[1480px]:grid-cols-3">{bullets.map((item,i)=><div key={i} className="flex gap-3 rounded-[22px] border border-white/30 bg-white/28 px-4 py-3 shadow-[inset_1px_1px_0_rgba(255,255,255,.48)] text-xs font-bold leading-5 text-muted 3xl:text-sm 3xl:leading-6"><span className="mt-2 h-2 w-2 shrink-0 rounded-full" style={{background:i===0?accent:i===1?'#8bbfe8':'#e8a6a6'}}/><span>{item}</span></div>)}</div></div></div></div></motion.section> }
function DraftFitMiniRow({ fit, index, accent }) { const blocked=fit.realism==='Blocked' || fit.label==='Blocked Fit', tone=blocked?'#a8844f':index===0?accent:'#8bbfe8', reason=(fit.reasons&&fit.reasons[0]) || fit.pickContext || 'Fit calculado por range, disponibilidade e contexto.'; return <motion.div whileHover={{x:3}} className={cn(glass.inner,'flex items-center gap-3 rounded-[28px] p-3 shadow-[0_12px_34px_rgba(40,36,32,.05),inset_1px_1px_0_rgba(255,255,255,.58)]', blocked?'opacity-65':'')}><TeamLogoGlass teamId={fit.teamId} size={index===0?'md':'sm'} showGlow={!blocked} muted={blocked}/><div className="min-w-0 flex-1"><div className="flex items-center gap-2"><span className="font-mono text-[8px] font-black uppercase tracking-[.18em] text-lo">#{index+1}</span><h4 className="truncate font-display text-lg font-black text-ink">{fit.teamName}</h4></div><p className="mt-1 line-clamp-1 text-xs font-bold text-muted">{reason}</p><div className="mt-2 flex flex-wrap gap-1.5"><span className="rounded-full border border-white/30 bg-white/30 px-2 py-0.5 font-mono text-[7px] font-black uppercase tracking-[.12em]" style={{color:tone}}>{fit.label}</span><span className="rounded-full border border-white/30 bg-white/20 px-2 py-0.5 font-mono text-[7px] font-black uppercase tracking-[.12em] text-lo">{fit.realism}</span></div></div><div className="font-numeric text-3xl font-extrabold leading-none" style={{color:tone}}>{Math.round(fit.score)}</div></motion.div> }
